import heapq

def astar(grid: list, start: tuple, goal: tuple) -> list:
    if start == goal:
        return [start]

    rows, cols = len(grid), len(grid[0])
    DIRECTIONS = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    def heuristic(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    # Min-heap: (f_score, g_score, node)
    # f = g + h
    h_start = heuristic(start, goal)
    heap = [(h_start, 0, start)]

    # g_score[node] = cost of cheapest known path from start to node
    g_score = {start: 0}

    # came_from[node] = parent node on the cheapest path
    came_from = {}

    # closed set: nodes already fully processed
    closed = set()

    while heap:
        f, g, current = heapq.heappop(heap)

        if current in closed:
            continue
        closed.add(current)

        if current == goal:
            # Reconstruct path
            path = []
            node = goal
            while node in came_from:
                path.append(node)
                node = came_from[node]
            path.append(start)
            return path[::-1]

        r, c = current
        for dr, dc in DIRECTIONS:
            nr, nc = r + dr, c + dc
            neighbor = (nr, nc)

            if not (0 <= nr < rows and 0 <= nc < cols):
                continue
            if grid[nr][nc] == 1:
                continue
            if neighbor in closed:
                continue

            tentative_g = g + 1  # Unit cost for each step
            if tentative_g < g_score.get(neighbor, float('inf')):
                g_score[neighbor] = tentative_g
                came_from[neighbor] = current
                h = heuristic(neighbor, goal)
                heapq.heappush(heap, (tentative_g + h, tentative_g, neighbor))

    return []  # No path found
